function make_palindrome(string) {
    if (string === "") return "";

    // Find the longest palindromic suffix
    let n = string.length;
    let bestSuffixStart = 0;

    for (let i = 0; i < n; i++) {
        // Check if substring from i to end is a palindrome
        if (isPalindrome(string, i, n - 1)) {
            bestSuffixStart = i;
            break;
        }
    }

    // The prefix before the palindromic suffix
    let prefix = string.substring(0, bestSuffixStart);
    // Reverse of the prefix
    let reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

function isPalindrome(str, start, end) {
    while (start < end) {
        if (str[start] !== str[end]) {
            return false;
        }
        start++;
        end--;
    }
    return true;
}
