function modp(n, p) {
    if (p === 1n) return 0n;

    const bigN = BigInt(n);
    const bigP = BigInt(p);

    // Compute 2^n % p using modular exponentiation
    let base = 2n;
    let exp = bigN;
    let result = 1n;

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % bigP;
        }
        base = (base * base) % bigP;
        exp = exp / 2n;
    }

    return Number(result);
}
