function circular_shift(x, shift) {
    let s = String(x);
    let n = s.length;

    if (shift > n) {
        return s.split('').reverse().join('');
    }

    // Right circular shift by shift positions
    // A right shift by k is equivalent to taking the last k characters and moving them to the front
    let effectiveShift = shift % n;
    if (effectiveShift === 0) {
        return s;
    }

    let shifted = s.slice(n - effectiveShift) + s.slice(0, n - effectiveShift);
    return shifted;
}
