    if (x === 1) {
        return true; // n^0 = 1 for any n != 0
    }

    if (n === 0) {
        return false; // 0^k = 0 for k > 0, and undefined/NaN for k=0 or negative
    }

    if (n === 1) {
        return x === 1; // 1^k = 1 for any k
    }

    if (n === -1) {
        return x === 1 || x === -1; // (-1)^k is either 1 or -1
    }

    let current = n;
    let power = 1;

    while (Math.abs(current) <= Math.abs(x)) {
        if (current === x) {
            return true;
        }
        power++;
        current *= n;

        // Prevent infinite loops and overflow
        if (power > 100) {
            break;
        }
    }

    return false;
}
