function simplify(x, n) {
    // Parse the fractions
    const [xNum, xDen] = x.split('/').map(Number);
    const [nNum, nDen] = n.split('/').map(Number);

    // Calculate x * n as a fraction: (xNum * nNum) / (xDen * nDen)
    const resultNum = xNum * nNum;
    const resultDen = xDen * nDen;

    // Check if the result is a whole number
    // A fraction is a whole number if the numerator is divisible by the denominator
    return resultNum % resultDen === 0;
}
