```javascript
function get_max_triples(n) {
    // Calculate the number of elements with remainder 0, 1, 2 when divided by 3
    let count = [0, 0, 0];

    for (let i = 1; i <= n; i++) {
        let val = i * i - i + 1;
        let rem = val % 3;
        count[rem]++;
    }

    // We need to find the number of triples (i, j, k) with i < j < k such that
    // a[i] + a[j] + a[k] is divisible by 3.
    // This means (a[i] % 3 + a[j] % 3 + a[k] % 3) % 3 == 0

    // Possible combinations of remainders that sum to 0 mod 3:
    // (0, 0, 0), (1, 1, 1), (2, 2, 2), (0, 1, 2)

    let result = 0;

    // Case 1: All three have remainder 0
    if (count[0] >= 3) {
        result += count[0] * (count[0] - 1) * (count[0] - 2) / 6;
    }

    // Case 2: All three have remainder 1
    if (count[1] >= 3) {
        result += count[1] * (count[1] - 1) * (count[1] - 2) / 6;
    }

    // Case 3: All three have remainder 2
    if (count[2] >= 3) {
        result += count[2] * (count[2] - 1) * (count[2] - 2) / 6;
    }

    // Case 4: One of each remainder 0, 1, 2
    result += count[0] * count[1] * count[2];

    return result;
}
