function right_angle_triangle(a, b, c) {
    // Sort the sides to identify the hypotenuse (longest side)
    const sides = [a, b, c].sort((x, y) => x - y);
    const [side1, side2, hypotenuse] = sides;

    // Check if it forms a valid triangle first (sum of any two sides > third side)
    if (side1 + side2 <= hypotenuse) {
        return false;
    }

    // Check Pythagorean theorem: a^2 + b^2 = c^2
    // Use a small epsilon for floating-point comparison
    const epsilon = 1e-9;
    return Math.abs(side1 * side1 + side2 * side2 - hypotenuse * hypotenuse) < epsilon;
}
