    if (!hasLetter) {
        return s.split('').reverse().join('');
    }

    let result = '';
    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (/[a-z]/.test(char)) {
            result += char.toUpperCase();
        } else if (/[A-Z]/.test(char)) {
            result += char.toLowerCase();
        } else {
            result += char;
        }
    }

    return result;
}
