```javascript
function factorize(n) {
  const factors = [];
  let d = 2;
  let temp = n;
  while (temp >= d * d) {
    while (temp % d === 0) {
      factors.push(d);
      temp /= d;
    }
    d++;
  }
  if (temp > 1) {
    factors.push(temp);
  }
  return factors;
}
```

