```javascript
function sort_third(l) {
  const divisibleByThreeIndices = [];
  const values = [];

  for (let i = 0; i < l.length; i++) {
    if (i % 3 === 0) {
      divisibleByThreeIndices.push(i);
      values.push(l[i]);
    }
  }

  values.sort((a, b) => a - b);

  const result = [...l];
  for (let i = 0; i < divisibleByThreeIndices.length; i++) {
    result[divisibleByThreeIndices[i]] = values[i];
  }

  return result;
}
