```javascript
function prime_fib(n) {
  function isPrime(num) {
    if (num < 2) return false;
    if (num === 2 || num === 3) return true;
    if (num % 2 === 0 || num % 3 === 0) return false;
    for (let i = 5; i * i <= num; i += 6) {
      if (num % i === 0 || num % (i + 2) === 0) return false;
    }
    return true;
  }

  let a = 0;
  let b = 1;
  let count = 0;

  while (count < n) {
    let next = a + b;
    a = b;
    b = next;
    if (isPrime(a)) {
      count++;
      if (count === n) return a;
    }
  }
}
```

