```javascript
function modp(n, p) {
  let res = 1n;
  let base = 2n;
  let exp = BigInt(n);
  let mod = BigInt(p);

  if (mod === 1n) return 0;

  base = base % mod;

  while (exp > 0n) {
    if (exp % 2n === 1n) {
      res = (res * base) % mod;
    }
    base = (base * base) % mod;
    exp = exp / 2n;
  }

  return Number(res);
}
```

