```javascript
function circular_shift(x, shift) {
  const s = x.toString();
  const n = s.length;

  if (shift > n) {
    return s.split('').reverse().join('');
  }

  const effectiveShift = shift % n;
  if (effectiveShift === 0) return s;

  const part1 = s.slice(n - effectiveShift);
  const part2 = s.slice(0, n - effectiveShift);
  return part1 + part2;
}
```

