```javascript
function is_simple_power(x, n) {
  if (x === 1) {
    return true;
  }
  if (n <= 1) {
    return x === n;
  }
  let current = n;
  while (current <= x) {
    if (current === x) {
      return true;
    }
    // Check for potential overflow/infinite loop if current exceeds x
    // but in JS numbers are floats, so we check multiplication
    let next = current * n;
    if (next === current && x !== current) {
        break;
    }
    current = next;
  }
  return false;
}
```

