```javascript
function starts_one_ends(n) {
  if (n === 1) {
    return 1;
  }

  // Total n-digit numbers: 9 * 10^(n-1)
  // Numbers starting with 1: 1 * 10^(n-1)
  // Numbers ending with 1: 9 * 10^(n-2) (first digit 1-9, last digit 1)
  // Numbers starting AND ending with 1: 1 * 10^(n-2) (first digit 1, last digit 1)

  // Using Inclusion-Exclusion Principle:
  // Count = |StartsWith1| + |EndsWith1| - |StartsAndEndsWith1|
  // Count = 10^(n-1) + 9 * 10^(n-2) - 10^(n-2)
  // Count = 10^(n-1) + 8 * 10^(n-2)

  // Since n can be large, we use BigInt to avoid precision issues
  const bigN = BigInt(n);
  const startsWith1 = 10n ** (bigN - 1n);
  const endsWith1 = 9n * (10n ** (bigN - 2n));
  const both = 10n ** (bigN - 2n);

  return Number(startsWith1 + endsWith1 - both);
}
```

