```javascript
function get_row(lst, x) {
  const result = [];

  for (let r = 0; r < lst.length; r++) {
    const rowCoords = [];
    for (let c = 0; c < lst[r].length; c++) {
      if (lst[r][c] === x) {
        rowCoords.push([r, c]);
      }
    }

    if (rowCoords.length > 0) {
      // Sort coordinates within the row by column index in descending order
      rowCoords.sort((a, b) => b[1] - a[1]);
      result.push(...rowCoords);
    }
  }

  // The outer loop already processes rows in ascending order.
  // Since we push row results sequentially, the final list is 
  // sorted by rows ascending, then columns descending within rows.
  return result;
}
```

```javascript
function sort_array(array) {
  if (array.length === 0) {
    return [];
  }
  if (array.length === 1) {
    return [...array];
  }

  const first = array[0];
  const last = array[array.length - 1];
  const isAscending = (first + last) % 2 !== 0;

  const sorted = [...array];

  if (isAscending) {
    sorted.sort((a, b) => a - b);
  } else {
    sorted.sort((a, b) => b - a);
  }

  return sorted;
}
```

```javascript
function encrypt(s) {
  return s.split('').map(char => {
    const code = char.charCodeAt(0);
    // Check if character is lowercase a-z
    if (code >= 97 && code <= 122) {
      return String.fromCharCode(((code - 97 + 4) % 26) + 97);
    }
    // Check if character is uppercase A-Z
    if (code >= 65 && code <= 90) {
      return String.fromCharCode(((code - 65 + 4) % 26) + 65);
    }
    // Return original character if not a letter
    return char;
  }).join('');
}
```

