```javascript
function encode(message) {
  const vowels = 'aeiouAEIOU';
  const getNextChar = (char) => {
    const code = char.charCodeAt(0);
    return String.fromCharCode(code + 2);
  };

  return message
    .split('')
    .map(char => {
      // Swap case
      let swapped = char === char.toUpperCase() 
        ? char.toLowerCase() 
        : char.toUpperCase();

      // Check if the original char was a vowel (to apply the shift on the swapped version)
      // The prompt implies replacing vowels in the message. 
      // Looking at example: "test" -> 'e' is vowel. 
      // 'e' swapped is 'E'. 'E' + 2 = 'G'. Result 'TGST'.
      // "This is a message" -> 'i' is vowel. 'i' swapped is 'I'. 'I' + 2 = 'K'.
      // So the logic is: 1. Swap case. 2. If the original char was a vowel, shift the NEW char by 2.

      if (vowels.includes(char)) {
        return getNextChar(swapped);
      }

      return swapped;
    })
    .join('');
}
```

