```javascript
function check_dict_case(dict) {
  const keys = Object.keys(dict);
  if (keys.length === 0) {
    return false;
  }

  // First, ensure all keys are strings and check their casing
  // Note: Object.keys returns strings, but we must verify they 
  // don't contain non-alphabetic characters that break the logic 
  // or aren't strictly upper/lower if we interpret "case" strictly.
  // However, based on examples, we check if they are all lower or all upper.

  let allLower = true;
  let allUpper = true;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];

    // Check if the key is purely lowercase
    if (key !== key.toLowerCase()) {
      allLower = false;
    }

    // Check if the key is purely uppercase
    if (key !== key.toUpperCase()) {
      allUpper = false;
    }

    // According to example {"a": "apple", 8: "banana"}, 
