function valid_date(date) {
  if (!date || typeof date !== 'string') {
    return false;
  }

  const parts = date.split('-');
  if (parts.length !== 3) {
    return false;
  }

  const mmStr = parts[0];
  const ddStr = parts[1];
  const yyyyStr = parts[2];

  // Check if parts are exactly 2 digits for month/day and 4 for year, 
  // and ensure they are numeric strings.
  if (mmStr.length !== 2 || ddStr.length !== 2 || yyyyStr.length !== 4) {
    return false;
  }

  const mm = parseInt(mmStr, 10);
  const dd = parseInt(ddStr, 10);
  const yyyy = parseInt(yyyyStr, 10);

  // Ensure they are valid numbers and not NaN
  if (isNaN(mm) || isNaN(dd) || isNaN(yyyy)) {
    return false;
  }

  // Rule 3: Month must be 1-12
  if (mm < 1 || mm > 12) {
    return false;
  }

  // Rule 2: Day validation based on month
  let maxDays;
  if ([1, 3, 5, 7, 8, 10, 12].includes(mm)) {
    maxDays = 31;
  } else if ([4, 6, 9, 11].includes(mm)) {
    maxDays = 30;
  } else if (mm === 2) {
    // Check for leap year
    const isLeap = (yyyy % 4 === 0 && yyyy % 100 !== 0) || (yyyy % 400 === 0);
    maxDays = isLeap ? 29 : 28;
  } else {
    return false;
  }

  if (dd < 1 || dd > maxDays) {
    return false;
  }

  // Final check to ensure format was mm-dd-yyyy and not something like 03-1-2000
  // by checking if the original string matches the re-constructed version
  // This handles cases like "03-0-2040" or non-numeric characters via parseInt behavior.
  const reconstructed = `${mmStr}-${ddStr}-${yyyyStr}`;
  if (reconstructed !== date) {
    return false;
  }

  return true;
}
