function minPath(grid, k) {
  const n = grid.length;
  const posMap = new Map();

  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      posMap.set(grid[r][c], [r, c]);
    }
  }

  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  // To find the lexicographically smallest path of length k:
  // We must greedily pick the smallest possible value for the first cell, 
  // then the smallest possible value for the second cell among its neighbors, and so on.
  // However, a simple greedy approach might lead to a dead end or a sub-optimal future.
  // BUT, since we can revisit cells, the "dead end" is not an issue (we can always move back).
  // The real constraint is: can we actually complete a path of length k?
  // Since N >= 2, every cell has at least 2 neighbors, so we can always move back and forth.
  // Therefore, the lexicographically smallest path is simply:
  // 1. Start at the cell with the minimum value in the whole grid.
  // 2. For each step, move to the neighbor with the minimum value.
  // 3. EXCEPT, there's a catch: the path is length k.
  // Let's reconsider: The path is [v1, v2, v3... vk].
  // To minimize this lexicographically, we want v1 to be as small as possible.
  // The smallest possible v1 is the minimum value in the grid.
  // Once v1 is chosen, we want v2 to be the smallest possible neighbor of v1.
  // Once v2 is chosen, we want v3 to be the smallest possible neighbor of v2.
  // This is true because we can always oscillate between the two smallest adjacent cells.

  // Wait, the rule is: v1 is the smallest in the grid.
  // v2 is the smallest neighbor of v1.
  // v3 is the smallest neighbor of v2.
  // ... and so on.

  // Let's find the global minimum value.
  let minVal = Infinity;
  let startPos = null;
  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      if (grid[r][c] < minVal) {
        minVal = grid[r][c];
        startPos = [r, c];
      }
    }
  }

  const path = [];
  let [currR, currC] = startPos;
  path.push(grid[currR][currC]);

  for (let i = 1; i < k; i++) {
    let bestNeighborVal = Infinity;
    let nextPos = [currR, currC];

    for (let d = 0; d < 4; d++) {
      const nr = currR + dr[d];
      const nc = currC + dc[d];

      if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
        if (grid[nr][nc] < bestNeighborVal) {
          bestNeighborVal = grid[nr][nc];
          nextPos = [nr, nc];
        }
      }
    }
    currR = nextPos[0];
    currC = nextPos[1];
    path.push(grid[currR][currC]);
  }

  return path;
}
