function is_nested(string) {
  let count = 0;
  let max_depth = 0;
  let current_depth = 0;

  for (let i = 0; i < string.length; i++) {
    if (string[i] === '[') {
      current_depth++;
      if (current_depth > max_depth) {
        max_depth = current_depth;
      }
    } else if (string[i] === ']') {
      current_depth--;
    }
  }

  // A valid nested subsequence exists if and only if 
  // we can find a pattern like "[[]]" within the string.
  // In terms of bracket logic, a string has a nested structure 
  // if it can form a pair that contains another pair.
  // The simplest way to check for a nested structure is to see 
  // if there's a point where the depth reaches at least 2 
  // while maintaining valid balance for that subsequence.

  // However, the prompt asks for a "valid subsequence".
  // A valid subsequence of brackets is nested if it's like "[[]]".
  // This is possible if and only if there is a '[' followed by another '[' 
  // and eventually two ']' that close them.
  // Simplified: if we can find "[[...]]" as a subsequence.
  // This is equivalent to: count of '[' >= 2 AND count of ']' >= 2 
  // AND there exists a way to pick them such that they nest.

  // Let's use a more robust approach:
  // Can we find a subsequence that is "[[]]"?
  // This requires finding '[' then '[' then ']' then ']' in that order.

  let stage = 0;
  for (let char of string) {
    if (stage === 0 && char === '[') stage = 1;
    else if (stage === 1 && char === '[') stage = 2;
    else if (stage === 2 && char === ']') stage = 3;
    else if (stage === 3 && char === ']') stage = 4;
  }

  return stage === 4;
}
