  // standing alone, preceded by a space (or being the only char).

  // Based on the examples:
  // "apple pie" -> 'e' is part of "pie" (length > 1) -> false
  // "apple pi e" -> 'e' is a single char word -> true
  // "apple pi e " -> last char is space -> false

