function file_name_check(file_name) {
  const parts = file_name.split('.');

  if (parts.length !== 2) {
    return 'No';
  }

  const namePart = parts[0];
  const extensionPart = parts[1];

  if (namePart.length === 0) {
    return 'No';
  }

  const firstChar = namePart[0];
  const isFirstCharLetter = (firstChar >= 'a' && firstChar <= 'z') || (firstChar >= 'A' && firstChar <= 'Z');
  if (!isFirstCharLetter) {
    return 'No';
  }

  const validExtensions = ['txt', 'exe', 'dll'];
  if (!validExtensions.includes(extensionPart)) {
    return 'No';
  }

  let digitCount = 0;
  for (let i = 0; i < file_name.length; i++) {
    if (file_name[i] >= '0' && file_name[i] <= '9') {
      digitCount++;
    }
  }

  if (digitCount > 3) {
    return 'No';
  }

  return 'Yes';
}
