function get_max_triples(n) {
    let counts = [0, 0, 0];
    for (let i = 1; i <= n; i++) {
        let val = i * i - i + 1;
        let remainder = val % 3;
        // Handle negative remainders if any, though not possible here given i >= 1
        if (remainder < 0) remainder += 3;
        counts[remainder]++;
    }

    let triples = 0;

    // Case 1: All three have the same remainder mod 3
    // Combination nC3 = n * (n-1) * (n-2) / 6
    for (let r = 0; r < 3; r++) {
        if (counts[r] >= 3) {
            triples += (counts[r] * (counts[r] - 1) * (counts[r] - 2)) / 6;
        }
    }

    // Case 2: All three have different remainders mod 3
    // remainder 0 + 1 + 2 = 3 (multiple of 3)
    // Number of ways = count[0] * count[1] * count[2]
    triples += counts[0] * counts[1] * counts[2];

    return triples;
}
