function right_angle_triangle(a, b, c) {
  const sides = [a, b, c].sort((x, y) => x - y);
  const [s1, s2, s3] = sides;

  // Check if it forms a valid triangle first (sum of two shorter sides > longest side)
  if (s1 + s2 <= s3) {
    return false;
  }

  // Pythagorean theorem: a^2 + b^2 = c^2
  // Using a small epsilon for floating point precision if necessary, 
  // but for integer inputs, strict equality works.
  return Math.pow(s1, 2) + Math.pow(s2, 2) === Math.pow(s3, 2);
