```javascript
function do_algebra(operator, operand) {
  const ops = {
    '+': (a, b) => a + b,
    '-': (a, b) => a - b,
    '*': (a, b) => a * b,
    '//': (a, b) => Math.floor(a / b),
    '**': (a, b) => Math.pow(a, b)
  };

  const precedence = {
    '**': 3,
    '*': 2,
    '//': 2,
    '+': 1,
    '-': 1
  };

  const values = [...operand];
  const operators = [...operator];

  const compute = () => {
    // We process operations based on precedence. 
    // Since the expression is linear (no parentheses), 
    // we can repeatedly find the highest precedence operator and apply it.
    while (operators.length > 0) {
      let highestPrecedence = -1;
      let targetIndex = -1;

      for (let i = 0; i < operators.length; i++) {
        if (precedence[operators[i]] > highestPrecedence) {
          highestPrecedence = precedence[operators[i]];
          targetIndex = i;
        }
      }

      // Note: For same precedence, standard math evaluates left-to-right.
      // However, exponentiation ** is usually right-to-left. 
      // But given the linear structure [op, op, op], we follow standard precedence rules.
      // To handle left-to-right for same precedence (like + and -), 
      // we should pick the FIRST occurrence of the highest precedence.
      // The loop above finds the first occurrence because of the '>' check.

      // Special case: exponentiation is right-associative, but in this linear 
      // array format [a, op, b, op, c], the problem implies standard order.
      // Let's refine the targetIndex selection for left-associativity.

      let bestIdx = 0;
      for (let i = 0; i < operators.length; i++) {
        if (precedence[operators[i]] > precedence[operators[bestIdx]]) {
          bestIdx = i;
        } else if (precedence[operators[i]] === precedence[operators[bestIdx]]) {
          // For same precedence, we want the leftmost one to maintain left-associativity
          // EXCEPT for exponentiation which is right-associative.
          // However, in most programming challenges of this type, 
          // simple left-to-right for same precedence is expected.
          // Let's stick to the first occurrence of the highest precedence.
          continue; 
        }
      }

      // Re-evaluating the loop logic to strictly follow precedence and left-associativity:
      let idx = -1;
      let maxP = -1;
      for(let i = 0; i < operators.length; i++) {
        if(precedence[operators[i]] > maxP) {
          maxP = precedence[operators[i]];
          idx = i;
        }
      }

      // If multiple operators have the same maxP, we must pick the one that 
      // satisfies associativity. Addition/Subtraction/Mult/Div are left-associative.
      // Exponentiation is right-associative.
      if (maxP === 3) { // Exponentiation
        // Find the RIGHTMOST exponentiation for right-associativity
        for(let i = operators.length - 1; i >= 0; i--) {
          if(precedence[operators[i]] === 3) {
            idx = i;
            break;
          }
        }
      } else {
        // Find the LEFTMOST for other operators
        for(let i = 0; i < operators.length; i++) {
          if(precedence[operators[i]] === maxP) {
            idx = i;
            break;
          }
        }
      }

      const val1 = values[idx];
      const val2 = values[idx + 1];
      const res = ops[operators[idx]](val1, val2);

      values.splice(idx, 2, res);
      operators.splice(idx, 1);
    }
    return values[0];
  };

  return compute();
}
