```javascript
function starts_one_ends(n) {
  if (n === 1) {
    return 1;
  }

  // Total n-digit numbers: 9 * 10^(n-1)
  // Numbers starting with 1: 1 * 10^(n-1)
  // Numbers ending with 1: 9 * 10^(n-2) (First digit 1-9, last digit 1, middle n-2 digits 0-9)
  // Numbers starting with 1 AND ending with 1: 1 * 1 * 10^(n-2)

  // Using Inclusion-Exclusion Principle:
  // Count = (Starts with 1) + (Ends with 1) - (Starts with 1 AND Ends with 1)

  const startsWithOne = Math.pow(10, n - 1);
  const endsWithOne = 9 * Math.pow(10, n - 2);
  const both = Math.pow(10, n - 2);

  return startsWithOne + endsWithOne - both;
}
