function solve(N) {
  // The prompt asks for "the total sum of its digits in binary".
  // However, the examples provided:
  // solve(1000) -> "1" (Binary 1000 is 1111101000, sum is 6. Wait, examples don't match description)
  // Let's re-examine the examples.
  // 1000 in binary is 1111101000. Sum of digits is 6.
  // 150 in binary is 10010110. Sum of digits is 4.
  // 147 in binary is 10010011. Sum of digits is 4.
  // The example outputs are "1", "110", "1100".
  // This suggests the function is not "sum of digits in binary", 
  // but rather something else.
  // Let's look at the pattern:
  // N=1000, Output="1"
  // N=150, Output="110"
  // N=147, Output="1100"
  // Let's look at the sum of digits in base 10?
  // 1000 -> 1+0+0+0 = 1. 1 in binary is "1".
  // 150 -> 1+5+0 = 6. 6 in binary is "110".
  // 147 -> 1+4+7 = 12. 12 in binary is "1100".
  // The pattern matches! The requirement "sum of its digits in binary" 
  // actually means "The binary representation of (the sum of the digits of N in base 10)".

  let sumOfDigits = N.toString().split('').reduce((acc, digit) => acc + parseInt(digit, 10), 0);
  return sumOfDigits.toString(2);
}
