function encode(message) {
  const vowels = 'aeiouAEIOU';
  return message.split('').map(char => {
    let transformed = char;

    // Handle vowel replacement first
    if (vowels.includes(char)) {
      const code = char.charCodeAt(0);
      // Check if it's uppercase or lowercase to maintain structure logic
      // though the prompt says swap case, we determine the target letter first
      // then apply the case swap to the final result.
      // However, the prompt implies: 1. swap case, 2. replace vowels.
      // Let's follow the logic: replace vowel with char 2 places ahead, THEN swap case.
      // Or swap case THEN replace?
      // Example "test" -> "TGST". 
      // 'e' is vowel. 2 ahead of 'e' is 'g'. 
      // Swap case of "test" -> "TEST". 
      // If we replace 'e' with 'g' in "test" -> "tgst", then swap case -> "TGST".
      // Example "This is a message" -> "tHKS KS C MGSSCGG"
      // 'i' -> 'k'. 'a' -> 'c'. 'e' -> 'g'.
      // "This" -> swap case -> "tHIS". 'i' becomes 'k' -> "tHKS". Correct.

      const nextChar = String.fromCharCode(code + 2);
      transformed = nextChar;
    }

    // Swap case
    if (transformed === transformed.toUpperCase()) {
      return transformed.toLowerCase();
    } else {
      return transformed.toUpperCase();
    }
  }).join('');
}
