```javascript
function check_dict_case(dict) {
  const keys = Object.keys(dict);
  if (keys.length === 0) {
    return false;
  }

  // In JS, Object.keys returns strings, but we should verify 
  // if the logic implies checking if the keys were originally 
  // something else. However, Object.keys converts all keys to strings.
  // The prompt example {"a": "apple", 8: "banana"} returns false.
  // In JS, dict[8] becomes dict["8"].
  // We must check if any key contains characters that aren't strictly 
  // letters to differentiate between a purely case-based check 
  // and a "is it all letters" check? 
  // Re-reading: "all keys are strings in lower case or all keys are strings in upper case".
  // The example {"a": "apple", 8: "banana"} returning false implies 
  // we should check if the key string representation matches the case pattern 
  // and if it contains non-alphabetic characters if we want to be strict.
  // But actually, the simplest interpretation:
  // Are all keys equal to their lowercase version?
  // Are all keys equal to their uppercase version?

  // Let's check the numeric example: 8 becomes "8". 
  // "8".toLowerCase() is "8", "8".toUpperCase() is "8".
  // If we use that, {"a": "apple", 8: "banana"} would return true 
  // because "a" is lowercase and "8" is lowercase.
  // BUT the example says it returns false. 
  // This implies "8" is neither lowercase nor uppercase? 
  // Or that keys must be alphabetic?
  // Let's check if the key is purely letters.

  let allLower = true;
  let allUpper = true;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];

    // Check if the key contains only letters (based on the "8" example)
    // If "8" makes it false, it means "8" is not considered a lowercase string 
    // or uppercase string in this context.
    const isAlpha = /^[a-zA-Z]+$/.test(key);
    if (!isAlpha) {
      return false;
    }

    if (key !== key.toLowerCase()) {
      allLower = false;
    }
    if (key !== key.toUpperCase()) {
      allUpper = false;
    }
  }

  return allLower || allUpper;
}
