function histogram(test) {
  if (!test || test.trim() === "") {
    return {};
  }

  const counts = {};
  const letters = test.split(/\s+/);
  let maxCount = 0;

  for (const char of letters) {
    if (char === "") continue;
    counts[char] = (counts[char] || 0) + 1;
    if (counts[char] > maxCount) {
      maxCount = counts[char];
    }
  }

  const result = {};
  for (const char in counts) {
    if (counts[char] === maxCount) {
      result[char] = maxCount;
    }
  }

  return result;
}
