function tri(n) {
  if (n < 0) return [];
  const res = new Array(n + 1);
  res[0] = 1; // Implicitly inferred from example: tri(3) -> [1, 3, 2, 8]
  // The example implies index 0 is 1, index 1 is 3, index 2 is 2, index 3 is 8.
  // Note: The prompt's description says tri(1)=3, tri(2)=2, tri(4)=3, tri(3)=8.
  // The example output [1, 3, 2, 8] shows:
  // arr[0] = 1 (placeholder/initial)
  // arr[1] = 3 (tri(1))
  // arr[2] = 2 (tri(2))
  // arr[3] = 8 (tri(3))

  for (let i = 1; i <= n; i++) {
    if (i % 2 === 0) {
      res[i] = 1 + i / 2;
    } else {
      // tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
      // This is a recursive definition that looks ahead.
      // However, for even i, tri(i) is known.
      // For odd i: tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
      // Since i+1 is even, tri(i+1) = 1 + (i+1)/2.
      // So tri(i) = tri(i-1) + tri(i-2) + (1 + (i+1)/2)
      const nextEven = 1 + (i + 1) / 2;
      const prev1 = i - 1 >= 1 ? res[i - 1] : 0;
      const prev2 = i - 2 >= 1 ? res[i - 2] : 0;

      // If i=1, tri(1) is explicitly given as 3.
      if (i === 1) {
        res[i] = 3;
      } else {
        res[i] = prev1 + prev2 + nextEven;
      }
    }
  }
  return res;
}
