function file_name_check(file_name) {
  const parts = file_name.split('.');

  // The file's name contains exactly one dot '.'
  if (parts.length !== 2) {
    return 'No';
  }

  const namePart = parts[0];
  const extensionPart = parts[1];

  // The substring before the dot should not be empty, 
  // and it starts with a letter from the latin alphabet
  if (namePart.length === 0 || !/^[a-zA-Z]/.test(namePart)) {
    return 'No';
  }

  // The substring after the dot should be one of these: ['txt', 'exe', 'dll']
  const validExtensions = ['txt', 'exe', 'dll'];
  if (!validExtensions.includes(extensionPart)) {
    return 'No';
  }

  // There should not be more than three digits ('0'-'9') in the file's name
  const digitCount = (file_name.match(/\d/g) || []).length;
  if (digitCount > 3) {
    return 'No';
  }

  return 'Yes';
}
