```javascript
function do_algebra(operator, operand) {
  const expression = [];
  for (let i = 0; i < operand.length; i++) {
    expression.push(operand[i]);
    if (i < operator.length) {
      let op = operator[i];
      if (op === '//') {
        op = '/'; // We will handle floor division manually or via Math.floor
      }
      expression.push(op);
    }
  }

  // Standard mathematical order of operations (PEMDAS/BODMAS)
  // Exponentiation (**)
  // Multiplication (*) and Floor Division (//)
  // Addition (+) and Subtraction (-)

  let tokens = [...operand];
  let ops = [...operator];

  // 1. Handle Exponentiation (**)
  for (let i = 0; i < ops.length; i++) {
    if (ops[i] === '**') {
      tokens[i] = Math.pow(tokens[i], tokens[i + 1]);
      tokens.splice(i + 1, 1);
      ops.splice(i, 1);
      i--;
    }
  }

  // 2. Handle Multiplication (*) and Floor Division (//)
  for (let i = 0; i < ops.length; i++) {
    if (ops[i] === '*' || ops[i] === '//') {
      if (ops[i] === '*') {
        tokens[i] = tokens[i] * tokens[i + 1];
      } else {
        tokens[i] = Math.floor(tokens[i] / tokens[i + 1]);
      }
      tokens.splice(i + 1, 1);
      ops.splice(i, 1);
      i--;
    }
  }

  // 3. Handle Addition (+) and Subtraction (-)
  let result = tokens[0];
  for (let i = 0; i < ops.length; i++) {
    if (ops[i] === '+') {
      result += tokens[i + 1];
    } else if (ops[i] === '-') {
      result -= tokens[i + 1];
    }
  }

  return result;
}
