    const isUpper = char === char.toUpperCase();
    const lower = char.toLowerCase();
    if (lower === 'a') return isUpper ? 'C' : 'c';
    if (lower === 'e') return isUpper ? 'G' : 'g';
    if (lower === 'i') return isUpper ? 'K' : 'k';
