function max_fill(grid, capacity) {
  let total_water = 0;
  for (let i = 0; i < grid.length; i++) {
    for (let j = 0; j < grid[i].length; j++) {
      if (grid[i][j] === 1) {
        total_water++;
      }
    }
  }

  let total_buckets_needed = 0;
  for (let i = 0; i < grid.length; i++) {
    let row_water = 0;
    for (let j = 0; j < grid[i].length; j++) {
      if (grid[i][j] === 1) {
        row_water++;
      }
    }
    total_buckets_needed += Math.ceil(row_water / capacity);
  }

  // The problem asks for the number of times you need to lower the buckets.
  // Since each well is a row, and each bucket has a fixed capacity,
  // and we must empty the wells, we calculate the buckets needed per row.

  let total_descents = 0;
  for (let i = 0; i < grid.length; i++) {
    let water_in_well = 0;
    for (let j = 0; j < grid[i].length; j++) {
      if (grid[i][j] === 1) {
        water_in_well++;
      }
    }
    total_descents += Math.ceil(water_in_well / capacity);
  }

