  // Which simplifies to (numX * numN) / (denX * denN)
  // A fraction is a whole number if the denominator divides the numerator perfectly.

  // Use BigInt to avoid precision issues with large numbers
  const numerator = BigInt(numX) * BigInt(numN);
  const denominator = BigInt(denX) * BigInt(denN);

