function minPath(grid, k) {
  const N = grid.length;
  const startVal = 1;
  let startPos = null;

  // Find the position of value 1
  for (let r = 0; r < N; r++) {
    for (let c = 0; c < N; c++) {
      if (grid[r][c] === 1) {
        startPos = [r, c];
        break;
      }
    }
    if (startPos) break;
  }

  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  /**
   * To find the lexicographically smallest path:
   * At each step, we want the smallest possible value.
   * However, choosing the smallest neighbor now might force us into 
   * a very large value later. 
   * 
   * But wait, the lexicographical comparison works from the first element.
   * So, the first element MUST be the smallest possible value we can start with.
   * Since we want to minimize the array [a1, a2, ..., ak], we must first
   * minimize a1. The smallest value in the grid is 1.
   * So a1 = 1.
   * Then, to minimize a2, we look at all neighbors of the cell containing 1
   * and pick the one with the smallest value.
   * Then, to minimize a3, we look at all neighbors of the cell containing 
   * the value we picked for a2, and pick the one with the smallest value.
   * 
   * Wait, is it that simple? Let's re-read.
   * "A path A is less than B if lst_A[i] < lst_B[i] at the first difference."
   * This is a greedy strategy. If we can pick a smaller value at step i,
   * it doesn't matter what happens at step i+1.
   * Therefore, the greedy choice is optimal.
   */

  let currentR = startPos[0];
  let currentC = startPos[1];
  const result = [grid[currentR][currentC]];

  for (let i = 1; i < k; i++) {
    let minNeighborVal = Infinity;
    let nextR = -1;
    let nextC = -1;

    for (let j = 0; j < 4; j++) {
      const nr = currentR + dr[j];
      const nc = currentC + dc[j];

      if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
        if (grid[nr][nc] < minNeighborVal) {
          minNeighborVal = grid[nr][nc];
          nextR = nr;
          nextC = nc;
        }
      }
    }

    currentR = nextR;
    currentC = nextC;
    result.push(grid[currentR][currentC]);
  }

  return result;
}
