function separate_paren_groups(paren_string) {
  const result = [];
  let currentGroup = "";
  let balance = 0;

  for (let char of paren_string) {
    if (char === "(") {
      balance++;
      currentGroup += char;
    } else if (char === ")") {
      balance--;
      currentGroup += char;
    }

    if (balance === 0 && currentGroup.length > 0) {
      result.push(currentGroup);
      currentGroup = "";
    }
  }

  return result;
