function pairs_sum_to_zero(l) {
  const seen = new Set();
  for (const num of l) {
    if (seen.has(-num)) {
      // We must ensure they are distinct indices. 
      // In this context, "distinct elements" usually refers to elements at different indices.
      // If the input is [0, 0], the sum is 0, and they are distinct elements.
      // However, if the input is [0], we cannot pick two.
      // Let's handle the 0 case specifically: if num is 0, we need to have seen another 0.
      // The set logic handles this if we check existence before adding.
      return true;
    }
    // Special handling for 0 to ensure we don't match a single 0 with itself
    // The logic `seen.has(-num)` already covers this because we check BEFORE adding.
    // But if l = [0], seen is empty, seen.has(0) is false, then we add 0.
    // If l = [0, 0], first 0: seen.has(0) is false, add 0. Second 0: seen.has(0) is true, return true.
    // This correctly identifies distinct elements at different indices.
    seen.add(num);
  }
  return false;
}
