  const result = [];
  let left = 0;
  let right = sorted.length - 1;

  while (left <= right) {
    result.push(sorted[left]);
    if (left < right) {
      result.push(sorted[right]);
    }
    left++;
    right--;
  }

  // The logic above might push the same element twice if not careful 
  // or mismatch the pattern for odd lengths. 
  // Let's refine the pointer logic to match: min, max, min, max...

  const finalResult = [];
  let l = 0;
  let r = sorted.length - 1;
  let toggle = true;

  while (l <= r) {
    if (toggle) {
      finalResult.push(sorted[l]);
      l++;
    } else {
      finalResult.push(sorted[r]);
      r--;
    }
    toggle = !toggle;
  }

  return finalResult;
}
