```javascript
function starts_one_ends(n) {
  if (n <= 0) return 0;
  if (n === 1) return 1;

  const pow10 = (exp) => Math.pow(10, exp);

  // Total numbers that start with 1: 10^(n-1)
  // Total numbers that end with 1: 9 * 10^(n-2) (if n > 1)
  // However, we need to count unique integers.
  // Let S be the set of n-digit integers starting with 1.
  // Let E be the set of n-digit integers ending with 1.
  // We want |S ∪ E| = |S| + |E| - |S ∩ E|

  // |S|: The first digit is 1. Remaining (n-1) digits can be anything from 0-9.
  // So |S| = 10^(n-1)

  // |E|: The last digit is 1. The first digit can be 1-9.
  // The remaining (n-2) digits can be 0-9.
  // So |E| = 9 * 10^(n-2)

  // |S ∩ E|: Starts with 1 AND ends with 1.
  // First digit is 1, last digit is 1. Remaining (n-2) digits can be anything.
  // So |S ∩ E| = 10^(n-2)

  // Result = 10^(n-1) + 9 * 10^(n-2) - 10^(n-2)
  // Result = 10^(n-1) + 8 * 10^(n-2)

  // Using BigInt to avoid precision issues for large n
  const big10 = BigInt(10);
  const big8 = BigInt(8);

  const s = big10 ** BigInt(n - 1);
  const e = BigInt(9) * (big10 ** BigInt(n - 2));
  const intersection = big10 ** BigInt(n - 2);

  return Number(s + e - intersection);
}
