function get_row(lst, x) {
  const result = [];

  for (let r = 0; r < lst.length; r++) {
    const rowCoords = [];
    for (let c = 0; c < lst[r].length; c++) {
      if (lst[r][c] === x) {
        rowCoords.push([r, c]);
      }
    }

    // Sort coordinates of the current row by columns in descending order
    rowCoords.sort((a, b) => b[1] - a[1]);

    // Add sorted row coordinates to the main result list
    for (const coord of rowCoords) {
      result.push(coord);
    }
  }

  // The outer loop naturally iterates through rows in ascending order
  // and we already sorted columns descending for each row.
  return result;
}
