function minPath(grid, k) {
  const n = grid.length;
  let minVal = Infinity;
  let startPos = null;

  // Find the minimum value in the grid to start the lexicographical smallest path
  for (let r = 0; r < n; r++) {
    for (let c = 0; c < n; c++) {
      if (grid[r][c] < minVal) {
        minVal = grid[r][c];
        startPos = [r, c];
      }
    }
  }

  // If k is 1, the path is just the minimum value
  if (k === 1) return [minVal];

  // To get the lexicographically smallest path, we must start at the minimum value.
  // After the first step, to keep the path minimal, we must move to the smallest
  // possible neighbor of the current cell.
  // However, if we need to make k > 2 moves, the best strategy is to move to the 
  // smallest neighbor and then immediately move back to the current cell (the global min)
  // if that neighbor allows a smaller sequence.
  // Actually, for k > 1, the path will always start with the global minimum.
  // The second element will be the smallest neighbor of the global minimum.
  // For the third element, we want to go back to the global minimum (since it's the smallest
  // possible value in the grid) if we can, or the smallest neighbor of that neighbor.
  // Wait: The path can visit the same cell multiple times.
  // Since the global minimum is the absolute smallest value in the grid,
  // any path of length k will want to spend as much time as possible on it.
  // If k is odd: min -> neighbor -> min -> neighbor ... -> min.
  // If k is even: min -> neighbor -> min -> ... -> neighbor.
  // But wait, if the neighbor of min is smaller than min, that's impossible by definition.
  // The only choice is which neighbor to pick. To minimize lexicographically,
  // we pick the neighbor with the smallest value.
  // Let's refine:
  // Step 1: minVal
  // Step 2: min(neighbors of minVal)
  // Step 3: minVal (because minVal is smaller than any other neighbor of the neighbor)
  // Step 4: min(neighbors of minVal)
  // and so on.

  const [r, c] = startPos;
  const neighbors = [];
  const dr = [-1, 1, 0, 0];
  const dc = [0, 0, -1, 1];

  for (let i = 0; i < 4; i++) {
    const nr = r + dr[i];
    const nc = c + dc[i];
    if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
      neighbors.push(grid[nr][nc]);
    }
  }

  const minNeighbor = Math.min(...neighbors);
  const result = [];
  for (let i = 0; i < k; i++) {
    if (i % 2 === 0) {
      result.push(minVal);
    } else {
      result.push(minNeighbor);
    }
  }

  return result;
}
