function get_max_triples(n) {
  // The elements are a[i] = i*i - i + 1 for i from 1 to n.
  // We need to find triples where (a[i] + a[j] + a[k]) % 3 == 0.
  // Let's analyze a[i] mod 3:
  // i % 3 == 1: (1)^2 - 1 + 1 = 1 % 3
  // i % 3 == 2: (2)^2 - 2 + 1 = 3 % 3 = 0
  // i % 3 == 0: (3)^2 - 3 + 1 = 7 % 3 = 1
  // So, a[i] % 3 is:
  // i % 3 == 1 => 1
  // i % 3 == 2 => 0
  // i % 3 == 0 => 1
  // Wait, let's re-check:
  // i = 1: 1 - 1 + 1 = 1
  // i = 2: 4 - 2 + 1 = 3 (0 mod 3)
  // i = 3: 9 - 3 + 1 = 7 (1 mod 3)
  // i = 4: 16 - 4 + 1 = 13 (1 mod 3)
  // i = 5: 25 - 5 + 1 = 21 (0 mod 3)
  // i = 6: 36 - 6 + 1 = 31 (1 mod 3)
  // The sequence mod 3 is: 1, 0, 1, 1, 0, 1, 1, 0, 1...
  // Pattern of i mod 3: 1, 2, 0, 1, 2, 0...
  // Pattern of a[i] mod 3: 1, 0, 1, 1, 0, 1, 1, 0, 1...
  // So:
  // if i % 3 == 1, a[i] % 3 = 1
  // if i % 3 == 2, a[i] % 3 = 0
  // if i % 3 == 0, a[i] % 3 = 1
  // Let's count counts of 0s, 1s, and 2s mod 3.

  let counts = [0, 0, 0]; // index 0: count of 0s, index 1: count of 1s, index 2: count of 2s

  for (let i = 1; i <= n; i++) {
    let val = (i * i - i + 1) % 3;
    counts[val]++;
  }

  let ans = 0;

  // Case 1: All three have same remainder mod 3 (0,0,0 or 1,1,1 or 2,2,2)
  // (0+0+0)%3=0, (1+1+1)%3=0, (2+2+2)%3=0
  for (let i = 0; i < 3; i++) {
    if (counts[i] >= 3) {
      ans += (counts[i] * (counts[i] - 1) * (counts[i] - 2)) / 6;
    }
  }

  // Case 2: One of each remainder (0, 1, 2)
  // (0+1+2)%3 = 3%3 = 0
  ans += counts[0] * counts[1] * counts[2];

  return ans;
}
