```javascript
function is_simple_power(x, n) {
  if (x < 1) return false;
  if (x === 1) return true;
  if (n <= 1) return false;

  let current = n;
  while (current <= x) {
    if (current === x) return true;
    // Prevent infinite loop if current grows too fast or doesn't reach x
    if (current > x / n) break;
    current *= n;
  }
  return false;
}
