```javascript
function starts_one_ends(n) {
  if (n <= 0) return 0;
  if (n === 1) return 1;

  // Total n-digit numbers is 9 * 10^(n-1)
  // Numbers starting with 1: 10^(n-1)
  // Numbers ending with 1: 9 * 10^(n-2)
  // Intersection (starts and ends with 1): 10^(n-2)

  // Using BigInt to prevent precision issues for large n
  const n_minus_1 = BigInt(n - 1);
  const n_minus_2 = BigInt(n - 2);

  const starts_with_1 = 10n ** n_minus_1;
  const ends_with_1 = 9n * (10n ** n_minus_2);
  const both = 10n ** n_minus_2;

  // Principle of Inclusion-Exclusion: A + B - (A ∩ B)
  const result = starts_with_1 + ends_with_1 - both;

  return Number(result);
}
