function check_dict_case(dict) {
  const keys = Object.keys(dict);
  if (keys.length === 0) {
    return false;
  }

  // First, ensure all keys are strings
  for (let key of keys) {
    if (typeof key !== 'string') {
      return false;
    }
  }

  let allLower = true;
  let allUpper = true;

  for (let key of keys) {
    if (key !== key.toLowerCase()) {
      allLower = false;
    }
    if (key !== key.toUpperCase()) {
      allUpper = false;
    }
    // If it's neither all lower nor all upper, we can fail early
    if (!allLower && !allUpper) {
      return false;
    }
  }

  return allLower || allUpper;
}
