  if (n < 2) {
    return [];
  }

  const primes = [];
  const isPrime = new Array(n).fill(true);
  isPrime[0] = false;
  isPrime[1] = false;

  for (let p = 2; p < n; p++) {
    if (isPrime[p]) {
      primes.push(p);
      for (let i = p * p; i < n; i += p) {
        isPrime[i] = false;
      }
    }
  }

  return primes;
}
