function move_one_ball(arr) {
  if (arr.length <= 1) {
    return true;
  }

  let drops = 0;
  let n = arr.length;

  for (let i = 0; i < n; i++) {
    if (arr[i] > arr[(i + 1) % n]) {
      drops++;
    }
  }

  // A sorted array that has been right-shifted will have at most one point 
  // where the next element is smaller than the current one (the "drop" point).
  // In a perfectly sorted array, there are 0 drops (considering circular wrap-around).
  // In a shifted sorted array, there is exactly 1 drop (at the wrap-around point).
  return drops <= 1;
}
