function get_odd_collatz(n) {
    let odds = [];
    let current = n;

    while (current !== 1) {
        if (current % 2 !== 0) {
            odds.push(current);
        }
        if (current % 2 === 0) {
            current = current / 2;
        } else {
            current = 3 * current + 1;
