function split_words(txt) {
  if (/\s/.test(txt)) {
    return txt.split(/\s+/);
  } else if (txt.includes(',')) {
    return txt.split(',');
  } else {
    let count = 0;
    for (let i = 0; i < txt.length; i++) {
      const charCode = txt.charCodeAt(i);
      if (charCode >= 97 && charCode <= 122) {
        const order = charCode - 97;
        if (order % 2 !== 0) {
          count++;
        }
      }
    }
    return count;
  }
}
