function prod_signs(arr) {
  if (arr.length === 0) {
    return undefined;
  }

  let productOfSigns = 1;
  let sumOfMagnitudes = 0;

  for (let i = 0; i < arr.length; i++) {
    const val = arr[i];
    sumOfMagnitudes += Math.abs(val);

    if (val > 0) {
      productOfSigns *= 1;
    } else if (val < 0) {
      productOfSigns *= -1;
    } else {
      productOfSigns *= 0;
    }
  }

  return sumOfMagnitudes * productOfSigns;
}
