function tri(n) {
  if (n < 0) return [];
  const res = new Array(n + 1);
  res[0] = 1; // Based on example tri(3) -> [1, 3, 2, 8], index 0 is 1
  if (n >= 1) res[1] = 3;

  for (let i = 2; i <= n; i++) {
    if (i % 2 === 0) {
      res[i] = 1 + i / 2;
    } else {
      // The definition for odd n depends on tri(n+1)
      // Since tri(n+1) where n is odd is an even number, 
      // tri(n+1) = 1 + (n+1)/2
      const nextEven = 1 + (i + 1) / 2;
      res[i] = res[i - 1] + res[i - 2] + nextEven;
    }
  }
  return res;
}
