function check_if_last_char_is_a_letter(txt) {
  if (txt.length === 0) {
    return false;
  }

  const lastChar = txt[txt.length - 1];
  const isLetter = /[a-zA-Z]/.test(lastChar);

  if (!isLetter) {
    return false;
  }

  // Check if the character is "not a part of a word".
  // According to the rules and examples:
  // "apple pie" -> false (e is part of the word 'pie')
  // "apple pi e" -> true (e is a single-character word)
  // "apple pi e " -> false (last char is a space, not a letter)

  // A character is "not part of a word" if it is a single-character word.
  // This means it must be preceded by a space and there must be nothing after it.
  // Since we already checked the last character is a letter, we just check if 
  // it's either the only character in the string or preceded by a space.

  if (txt.length === 1) {
    return true;
  }

  return txt[txt.length - 2] === ' ';
}
