function get_max_triples(n) {
  let counts = [0, 0, 0];
  for (let i = 1; i <= n; i++) {
    let val = (i * i - i + 1) % 3;
    // Note: in JS, % can return negative for negative numbers, 
    // but i*i - i + 1 is always positive for i >= 1.
    counts[val]++;
  }

  let result = 0;

  // Case 1: All three numbers have the same remainder modulo 3
  // Combinations: nC3 = n * (n-1) * (n-2) / 6
  for (let i = 0; i < 3; i++) {
    if (counts[i] >= 3) {
      result += (counts[i] * (counts[i] - 1) * (counts[i] - 2)) / 6;
    }
  }

  // Case 2: All three numbers have different remainders modulo 3 (0, 1, 2)
  // Combinations: count[0] * count[1] * count[2]
  result += counts[0] * counts[1] * counts[2];

  return result;
}
